"""
MKT Original Layer — Ezekiel chapters 29–32
Run: python3 scripts/zc-original-ezekiel-29-32-fill.py

Four Oracles Against Egypt — the longest OAN section in Ezekiel.

Key lexical clusters:
- Ch 29: tannin (H8577, sea dragon/crocodile) for Pharaoh; "my Nile — I made it"
  (creature claiming creator-rights); mishenet qaneh (staff of reed = unreliable
  Egypt); qeren (horn = royal power, v.21).
- Ch 30: yom-YHWH (Day of the LORD) against Egypt; gillulim at Memphis;
  zero'a (arm/strength) broken and strengthened.
- Ch 31: Cedar of Lebanon allegory; gan-el/Eden trees (garden of God);
  Sheol descent; tehom (the deep); pride that leads to the Pit.
- Ch 32: Tannin in the seas (second time); cosmic darkness; the underworld
  roll-call (Assyria, Elam, Meshech-Tubal, Edom, Sidon) — all
  'uncircumcised, slain by the sword' sharing Egypt's shame.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EZK_ORIG = {
  "29": {
    "1": "<p>Precise date: tenth year, tenth month, twelfth day — January 587 BCE, during the final siege of Jerusalem. The oracle against Egypt is contemporary with the most intense phase of the Babylonian siege, when Israel's hope in Egyptian intervention was at its highest. Ezekiel speaks against the very power his people are counting on.</p>",
    "2": "<p><strong>sim panecha al-paro melek mitzraim</strong> ('set your face against Pharaoh king of Egypt'): the <em>sim panim el</em> formula is Ezekiel's distinctive confrontational stance — the prophet's embodied posture of opposition (cf. 6:2; 13:17; 25:2; 28:21). The whole land of Egypt is judged through its king; Pharaoh embodies the national claim to divine status.</p>",
    "3": "<p><strong>hatannim haggadol harobetz betoch yeorah</strong> ('the great sea dragon/crocodile lying in the midst of his rivers'): <em>tannin</em> (H8577, sea monster/dragon/large reptile) — the chaos-monster vocabulary of Gen 1:21 (God created the great sea creatures); Ps 74:13-14 (you crushed the heads of the sea monster; you crushed the heads of Leviathan); Isa 27:1. Pharaoh as the embodiment of chaos lying in the Nile. <strong>li yeori vaani asitini</strong> ('my Nile is mine — I made it'): the creature claiming creator-rights, the ultimate act of creature-hubris. The Nile was treated as divine in Egyptian religion (<em>Hapy</em>, the Nile flood god). YHWH attributes this self-deification directly to Pharaoh as the arrogance that warrants judgment.</p>",
    "4": "<p><strong>venatatti chchachim bilichyeycha</strong> ('I will put hooks in your jaws'): the great fish hooked and hauled out — a reversal of the dragon's dominion over the waters. The same imagery of divine sovereignty over sea-monsters appears in Job 40:24-25 (can you put a hook in Leviathan's jaw?); YHWH's ability to hook the chaos-dragon is the claim to ultimate sovereignty. <em>qasqaset</em> (H7193, scales/armor-plating of fish/reptile) — the dragon's natural armor is no protection against YHWH.</p>",
    "5": "<p><strong>unetattikha el-hamidbar otcha vekhol-degat yeorecha</strong> ('I will throw you into the wilderness, you and all the fish of your Nile'): the Egypt-dragon thrown into the desert — the reversal of Egypt's entire civilization which depended on the Nile. <strong>al-penei hassadeh tipol</strong> ('you will fall in the open fields, not gathered or collected'): proper burial was enormously important in Egyptian culture (the entire elaborate mortuary industry). To lie unburied in the open field, exposed to scavengers, was the ultimate disgrace. <strong>lechayyat haaretz ulelof hashamayim</strong> ('food to the beasts of the field and birds of the air'): the exact reversal of Egyptian animal veneration — the sacred ibis and crocodile become consumers of Egypt's corpse.</p>",
    "6": "<p><strong>veyadefu kol-yoshevei mitzraim ki ani YHWH</strong> ('all the inhabitants of Egypt will know that I am the LORD'): the recognition formula applied to a foreign nation — YHWH's self-disclosure extends beyond Israel. <strong>yaan heyotam lemishenet qaneh</strong> ('because they have been a staff of reed'): <em>mishenet</em> (H4938, staff/support) + <em>qaneh</em> (H7070, reed/cane) — the hollow reed that looks like a staff but splinters when leaned on. The reed staff is the central image of the oracle: Egypt's military alliance is structurally unreliable.</p>",
    "7": "<p><strong>beachozam becha vekhappecha</strong> ('when they grasped you with their hand'): the literal image of clutching a reed staff — it shatters and pierces the hand that grips it. <strong>ushavarta lahem kol-katef</strong> ('you shattered/broke for them every shoulder'): the staff that breaks and twists the shoulder of the one leaning on it. The political theology: alliances with Egypt consistently injured Israel rather than supporting it (Isa 30:3-7; 31:1-3). The reed staff oracle interprets a consistent historical pattern.</p>",
    "8": "<p>The sword oracle against Egypt — <em>heveiti alayich cherev</em> ('I will bring a sword against you'): the Babylonian sword as YHWH's instrument. <em>vechikhrati mimech adam uvehemah</em> ('I will cut off both human and animal'): comprehensive desolation — not just military defeat but demographic and agricultural collapse.</p>",
    "9": "<p><strong>vehaytah eretz mitzraim lishemamah uvechorvah</strong> ('the land of Egypt will become a desolation and a waste'): <em>shemamah</em> (H8077, desolation/devastation) + <em>chorbah</em> (H2723, ruin/waste) — the covenant-curse pair appearing throughout the OAN sections and in the Jerusalem oracles. The cause: <em>yaan amar yeori li vaani asitiv</em> — 'because he said the Nile is mine and I made it.' The theological arrogance of v.3 is the explicit grounds of the judgment.</p>",
    "10": "<p><strong>mimmigdol seveneh vead gevul kush</strong> ('from Migdol to Syene, as far as the border of Cush'): the geographical formula for all of Egypt — from the northeastern delta (Migdol, on the Sinai border) to the southern extreme (Syene = Aswan, at the first cataract). The judgment covers the entire land without exception.</p>",
    "11": "<p><strong>arbaim shanah</strong> ('forty years'): the wilderness-generation period applied to Egypt — forty years of desolation mirrors Israel's forty years in the wilderness as a generation of judgment. This is a round number for a complete period of divine discipline. Historical records suggest a Babylonian campaign against Egypt under Nebuchadnezzar (568-567 BCE) but the land was not uninhabited for forty literal years; the number carries symbolic weight.</p>",
    "12": "<p><strong>vehapitzoti et-mitzraim bagoyim</strong> ('I will scatter the Egyptians among the nations'): the same diaspora-language used of Israel's punishment applied to Egypt. The judgment of the nations mirrors the judgment of Israel, demonstrating YHWH's universal sovereignty. No nation is exempt from the same covenant-logic that governs Israel's history.</p>",
    "13": "<p><strong>veqibatzti et-mitzraim min-haamim asher-naphutzu shamah</strong> ('I will gather the Egyptians from the peoples'): the remarkable restoration promise — even Egypt receives a measure of the return-from-exile that Israel will receive. YHWH's purposes for Egypt include eventual restoration, though not to their former greatness.</p>",
    "14": "<p><strong>veshavti et-shevut mitzraim</strong> ('I will restore the fortunes of Egypt'): the <em>shuv shevut</em> (H7725 + H7622, 'restore fortunes/restore captivity') formula — the same idiom used for Israel's restoration (Jer 30:3,18; 31:23; Ezek 39:25). Egypt will return to Pathros (<em>Pathros</em> = Upper Egypt, the traditional homeland of Egyptian civilization). <strong>mamlakhah shephalah tihyeh</strong> ('there they will be a lowly/humble kingdom'): <em>shephel</em> (H8217, lowly/humble) — Egypt will survive but will never again be a great power claiming divine status for its river and kings.</p>",
    "15": "<p><strong>min-hamamelechet hishphal tihyeh</strong> ('it will be the humblest of kingdoms'): the permanent diminishment of Egypt as the eschatological outcome. The proud civilization that claimed self-creation will be preserved in a humble form, no longer posing a spiritual or political threat to Israel through unreliable alliances. This is the 'lowering the proud, lifting the humble' principle (Ezek 21:26-27; Luke 1:52-53).</p>",
    "16": "<p><strong>velo yihyeh od liveit yisrael lemivtach</strong> ('Egypt will no longer be a source of confidence/trust for the house of Israel'): <em>mivtach</em> (H4009, security/confidence/object of trust) — derived from <em>batach</em> (H982, to trust/rely on). The root of Israel's Egyptian alliance-problem was misplaced <em>bitachon</em> — trusting Egypt instead of YHWH (Isa 30:1-5; 31:1; Jer 17:5-8). The oracle resolves the problem at its source: Egypt's reduction eliminates the temptation.</p>",
    "17": "<p>Latest-dated oracle in Ezekiel: twenty-seventh year, first month, first day — April 571 BCE, some sixteen years after the fall of Jerusalem (586 BCE). The Tyre oracle (ch 26-28) promised Nebuchadnezzar the plunder of Tyre; the historical Tyre campaign (585-572 BCE) ended without the promised plunder, so YHWH redirects the payment to Egypt.</p>",
    "18": "<p><strong>nebuchadretstsar melech bavel he'evid et-cheilo avodah gedolah el-tzor</strong> ('Nebuchadnezzar made his army labor strenuously against Tyre'): <em>avodah gedolah</em> ('great labor/service') — the thirteen-year siege of Tyre was one of the most exhausting campaigns in ancient Near Eastern history. <strong>kol-rosh muqrach vekhol-kateph murad</strong> ('every head was bald and every shoulder was rubbed raw'): vivid imagery of the physical toll — helmets wearing away hair, equipment chafing shoulders. Despite the effort, Tyre's island position meant much of the city's wealth had been evacuated by sea.</p>",
    "19": "<p><strong>noten et-eretz mitzraim linebuchadretstsar melech bavel</strong> ('I am giving the land of Egypt to Nebuchadnezzar'): YHWH as the sovereign who assigns nations as payment for services rendered to his purposes. The theological point: even pagan military campaigns against other pagan powers serve YHWH's overarching plan. Nebuchadnezzar is 'my servant' (Jer 27:6) — given Egypt as wages.</p>",
    "20": "<p><strong>ucheret lo et-eretz mitzraim bescharoh asher-avad bi</strong> ('I have given him the land of Egypt as his wage for what he did, because he worked for me'): the astonishing claim — a pagan king 'working for YHWH' without knowing it (cf. Isa 44:28-45:1 on Cyrus; Acts 4:27-28 on Herod and Pilate). The divine economy compensates its instruments; even Nebuchadnezzar receives his wage.</p>",
    "21": "<p><strong>bayyom hahu atzmichai qeren leveit yisrael</strong> ('on that day I will cause a horn to sprout for the house of Israel'): <em>qeren</em> (H7161, horn) — the symbol of royal power and strength (Ps 92:10; 132:17 'I will cause David's horn to bud'; Lk 1:69 'raised up a horn of salvation in the house of David'). The Egypt oracle, after all its prophecy of judgment, closes with a restoration promise for Israel: the same day Egypt is humbled, Israel's royal power is renewed. <strong>eftach-picha betovchem</strong> ('I will open your mouth among them'): the recommissioning of Ezekiel's prophetic speech (cf. 3:26-27; 33:22).</p>"
  },
  "30": {
    "1": "<p>Oracle formula without date — the undated position suggests this oracle extends the Egypt judgment section as a poetic complement to the dated prose oracles.</p>",
    "2": "<p><strong>heylilu al-hayyom</strong> ('wail! alas for the day!'): the opening lament-cry — <em>heylel/yalal</em> (H3213, wail/howl) — onomatopoeic mourning. <strong>hayyom</strong> ('the day') — the ominous definite article: a specific day of reckoning is coming, not a general future.</p>",
    "3": "<p><strong>ki qarov yom veqarov yom laYHWH</strong> ('for the day is near — the day of the LORD is near'): the only explicit <em>yom YHWH</em> in the Ezekiel OAN section. The Day of the LORD against Egypt — the concept developed in Amos 5:18-20 (for Israel); Isa 13 (against Babylon); Joel; now applied to Egypt. <em>et goyim</em> ('time/appointed time of the nations') — the Day is not Israel-specific but universal: it applies to all nations that have set themselves against YHWH's purposes.</p>",
    "4": "<p><strong>ubaa cherev bemitzraim</strong> ('the sword will come against Egypt'): the Babylonian sword as divine instrument. <strong>chavlah cush</strong> ('anguish will grip Ethiopia'): Egypt's southern ally suffers collateral damage — the 'anguish' (<em>chil</em>, H2427, writhing pain/anguish, as in labor pangs) is the shock of seeing the dominant regional power fall.</p>",
    "5": "<p>The coalition list: Cush, Put, Lud, mixed peoples (<em>erev</em>, H6153/6154), Cub — the nations allied with or dependent on Egypt. <em>erev</em> ('mixed peoples') may be the same as 'mixed multitude' (Exod 12:38 — non-Israelites who joined the Exodus). The Egyptian coalition represents the multiplicity of nations that have organized their security around Egyptian power rather than YHWH.</p>",
    "6": "<p><strong>ga'on uzza tarda</strong> ('her proud strength will collapse'): <em>gaon</em> (H1347, pride/majesty/excellence) applied to Egypt's power — the same word Ezekiel uses for Israel's pride (7:24) and Assyria's (32:12). <em>ga'on</em> is what YHWH consistently opposes: 'every proud one is an abomination to YHWH' (Prov 16:5). Egypt's <em>gaon</em> — built on the claim to divine self-creation of the Nile — is precisely what the judgment dismantles.</p>",
    "7": "<p>Desolation formula — the same geographical sweep as 29:10 (Migdol to Syene). The repetition across multiple oracles reinforces the comprehensiveness of the judgment and establishes the established fact through multiple witnesses (Deut 19:15: a matter is established by two or three witnesses).</p>",
    "8": "<p><strong>veyadefu ki ani YHWH beshtoni esh bemitzraim</strong> ('they will know that I am the LORD when I set fire to Egypt'): the recognition formula again — but for Egypt's helpers, not only Egypt. The circle of YHWH's self-revelation through judgment extends to all who supported Egypt, including those nations who thought their security lay in Egyptian alliance.</p>",
    "9": "<p><strong>biqqayot yetzeyu miti lepahad kush batach</strong> ('messengers will go out by ship to terrify complacent Cush'): <em>batach</em> (H982, secure/complacent/at ease) — Ethiopia's false security. The same root as <em>mivtach</em> (v.16 in ch 29): trust/security placed in human power rather than YHWH. The fast-moving messengers by boat (along the Nile) carrying news of Egypt's fall: the speed of news transmission in antiquity was along waterways.</p>",
    "10": "<p><strong>vehishbati et-hamon mitzraim beyad nebuchadretzar</strong> ('I will put an end to the multitude of Egypt by the hand of Nebuchadnezzar'): <em>hamon</em> (H1995, multitude/crowd/noise/wealth) — Egypt's vast population and resources. The <em>hamon</em> that makes Egypt impressive is what YHWH will terminate. Nebuchadnezzar is explicitly named as YHWH's instrument — the Babylonian king who acts without knowing that he serves the divine purpose.</p>",
    "11": "<p><strong>araritzei goyim</strong> ('the most ruthless of nations'): Ezekiel's characteristic description of Babylon (28:7; 30:11; 31:12; 32:12) — <em>aritz</em> (H6184, ruthless/violent/terrifying). The ruthlessness that is morally problematic in itself is used as YHWH's instrument. Divine sovereignty working through imperfect instruments is a constant in Ezekiel's theology of history.</p>",
    "12": "<p><strong>venatatti yeoroth charavah</strong> ('I will make the Nile channels run dry'): the drying of the Nile — the reversal of Egypt's foundational water-source, directly answering Pharaoh's claim 'My Nile is mine.' <strong>umakarti et-haaretz beyad-reim</strong> ('I will sell the land into the hand of evil men'): <em>makar</em> (H4376, sell) — YHWH selling Egypt, suggesting Egypt's own subordinate status to divine sovereignty; <em>ra</em> (H7451, evil/bad) applied to the Babylonian conquerors.</p>",
    "13": "<p><strong>vehishbati gillulim</strong> ('I will destroy the idols'): <em>gillulim</em> in Memphis (Noph) — the demolition of Egypt's cultic statuary. Memphis was the ancient capital and religious center, home to the Ptah temple and the Apis bull cult. <strong>venassi mieretz mitzraim lo yihyeh od</strong> ('there will no longer be a prince in the land of Egypt'): the political and cultic structures collapse simultaneously — religious and political power are co-terminal.</p>",
    "14": "<p>Egyptian geography: <em>Pathros</em> = Upper Egypt; <em>Zoan</em> = Tanis in the eastern delta (where the Israelites labored, Ps 78:43); <em>No</em> = Thebes (<em>No-Amon</em> in Nah 3:8), the great temple city of Amon-Ra. The judgment reaches the entire Nile valley from south to north, targeting each major religious center.</p>",
    "15": "<p><strong>veshafachti chamati al-sin</strong> ('I will pour out my wrath on Pelusium'): <em>sin/sewen</em> = Pelusium, the northeastern fortress-gateway to Egypt from Sinai — the military key to Egypt's eastern defense. <strong>uveratii et-hamon No</strong> ('and cut off the multitude of Thebes'): Thebes, the wealthiest city in the ancient world (Homer, Iliad 9.381: 'Egyptian Thebes where the treasure-houses are fullest'), the religious heart of Egypt.</p>",
    "16": "<p>The cascade of Egyptian cities — Pelusium, Thebes, Memphis — three strategic centers of power facing destruction simultaneously. The three cities represent Egypt's military gateway (Pelusium), religious heart (Thebes/Amon), and administrative capital (Memphis/Ptah).</p>",
    "17": "<p><em>On</em> = Heliopolis, the center of the Ra/sun cult (Gen 41:45 — Potiphera, Joseph's father-in-law, was priest of On). <em>Pi-beseth</em> = Bubastis, center of the Bastet (cat-goddess) cult. Two of Egypt's primary religious cities face military destruction — the judgment targets the cultic infrastructure specifically.</p>",
    "18": "<p><strong>vetachpanches chasakh hayyom</strong> ('at Tahpanhes the day will grow dark'): Tahpanhes = Daphne, the garrison city in the eastern delta where Jeremiah was taken after the assassination of Gedaliah (Jer 43:7-9). <strong>beshivri sham et-mattot mitzraim</strong> ('when I break the yokes of Egypt there'): <em>matteh</em> (H4294, rod/yoke/tribe) — the breaking of Egypt's dominion-rods, the power that Egypt exercised over neighboring peoples.</p>",
    "19": "<p><strong>veasiti shephath bivmitzraim</strong> ('thus I will execute judgments in Egypt'): the chapter concludes with the recognition formula — <em>veyadu ki-ani YHWH</em>. The entire oracle is structured as a theodicy: these judgments are not arbitrary displays of power but the execution of covenant justice that will result in the knowledge of YHWH among the nations.</p>",
    "20": "<p>New date: eleventh year, first month, seventh day — April 587 BCE, one year after the ch 29 oracle, still during the Jerusalem siege. The arm-breaking oracle interprets the failure of Pharaoh Hophra's attempted intervention against Babylon (Jer 37:5-8) as YHWH's action.</p>",
    "21": "<p><strong>et-zero'a paro</strong> ('the arm of Pharaoh king of Egypt'): <em>zero'a</em> (H2220, arm/strength/power) — the arm as the symbol of military power (Ps 44:3; 77:15; Isa 51:5,9). <strong>lo-chatash lashum chatvulot</strong> ('it has not been bound up to heal it, no bandage applied'): the wound that is not treated — the military debacle of Hophra's failure to relieve Jerusalem. The army that failed to help Israel has no healing; its defeat is permanent.</p>",
    "22": "<p><strong>veshivarti et-zero'otav et-hachazaqah veeth-hanishbaret</strong> ('I will break his arms, both the strong and already-broken one'): both arms broken — total military incapacitation. The complete disabling of Egyptian military power means no help can come from that quarter. <strong>vehipalti et-hacharev miyado</strong> ('I will make the sword fall from his hand'): the disarmed Pharaoh, unable even to hold a weapon, much less wield it in Israel's defense.</p>",
    "23": "<p><strong>vahapitzoti et-mitzraim bagoyim</strong> ('I will scatter the Egyptians among the nations'): the diaspora-formula for Egypt — the same verb (<em>putz</em>, H6327, scatter/disperse) used for Israel's exile. In the divine economy, all nations are subject to the same covenant-logic: pride leads to scattering; humility enables gathering.</p>",
    "24": "<p><strong>vehizzaqti et-zero'ot melek bavel</strong> ('I will strengthen the arms of the king of Babylon'): the contrast with broken Pharaoh-arms — YHWH breaks Egyptian arms and strengthens Babylonian arms. <em>zero'a melek bavel</em> versus <em>zero'a paro</em>: the same word (<em>zero'a</em>) used for both, with YHWH controlling which is strong and which is broken. <strong>venatatif et-charvi beyado</strong> ('I will put my sword in his hand'): Nebuchadnezzar wielding YHWH's sword — the pagan king as the divine executor of judgment.</p>",
    "25": "<p><strong>veyadu ki-ani YHWH benitni charevi beyad melek bavel</strong> ('they will know that I am the LORD when I put my sword in the hand of the king of Babylon'): the recognition formula is attached to the action through a pagan king — YHWH's self-disclosure happens through the unexpected agent. The Babylonian king is the instrument; YHWH is the sovereign. This is the theological key to understanding geopolitical history in Ezekiel.</p>",
    "26": "<p>The concluding formula of the arm-oracle restates the scattering of Egypt (<em>vahapitzoti et-mitzraim</em>) and the recognition formula (<em>veyadu ki-ani YHWH</em>). The chapter ends as it began: YHWH is the subject; Egypt's humiliation is the means of universal knowledge of the LORD.</p>"
  },
  "31": {
    "1": "<p>Date: eleventh year, third month, first day — June 587 BCE, still before Jerusalem's fall. The cedar of Lebanon allegory responds to Pharaoh's implied claim to greatness comparable to Assyria's.</p>",
    "2": "<p><strong>el mi damita vegadlecha</strong> ('whom are you like in your greatness?'): the rhetorical question that opens the comparison — Ezekiel will answer it with the Assyrian cedar, then with the Eden trees. The question's form presupposes that Pharaoh has compared himself to great powers; YHWH will use that comparison to bring him down.</p>",
    "3": "<p><strong>hineh ashur erez balevanon</strong> ('consider: Assyria was a cedar in Lebanon'): <em>erez</em> (H730, cedar) — the royal tree of the ancient Near East, used for palace and temple construction throughout the region (Solomon's temple used Phoenician cedar; Sennacherib's annals boast of cutting cedars). The cedar in Lebanon as the paradigm of greatness: the tallest trees in the world, fragrant, prized, associated with divinity. <strong>vemareh yophi</strong> ('beautiful in appearance'): <em>yapheh</em> (H3303, beautiful/fair) — the same word used for the tree of the knowledge of good and evil in Gen 3:6. Beauty that leads to pride and fall is a consistent biblical pattern.</p>",
    "4": "<p><strong>mayim gidluhu</strong> ('the waters made it great'): <em>tehom</em> (H8415, the deep/primordial waters) raising the cedar — the cosmic deep waters that appear in Gen 1:2 as the primordial chaos now serve a fertilizing function. The deep waters irrigating the cosmic tree connect this vision to the Eden imagery: the river in Eden (Gen 2:10) watered the garden. The cedar fed by <em>tehom</em> is sustained by the same waters that the creation narrative assigns to YHWH's sovereignty.</p>",
    "5": "<p><strong>al-ken gavhah qomato mikol atzei hassadeh</strong> ('therefore it grew taller than all the trees of the field'): the height as the result of the deep-water nourishment. The vertical axis — height — is the spatial metaphor for power and pride. What grows tallest is most visible, most admired, and most exposed to the wind. The anatomy of pride: nourished by resource; expressed in height; exposed in fall.</p>",
    "6": "<p><strong>bise'ipotav qinenu kol-of hashamayim</strong> ('in its boughs all the birds of the sky nested'): the cosmic-tree motif — the great tree as the dwelling of all creatures. This imagery appears in Daniel 4:12 (Nebuchadnezzar's dream of the cosmic tree under which all beasts sheltered) and in Jesus's parable of the mustard seed (Matt 13:32: 'birds of the air come and perch in its branches'). The tree that shelters all living things is both imperial symbol and creation-order image.</p>",
    "7": "<p><strong>yapheh gadlo ve-orech daliyotav</strong> ('beautiful in its greatness, magnificent in the length of its branches'): <em>yapheh</em> again — beauty that will become the grounds of the comparison with Eden (v.8-9) and therefore the grounds of the fall. What is most beautiful and most admired is closest to the pride that triggers judgment.</p>",
    "8": "<p><strong>aratzim lo adaduhu began elohim</strong> ('the cedars in the garden of God could not match him'): the explicit Eden-garden comparison. <em>gan elohim</em> (H1588 + H430, 'garden of God') = the garden of Eden (cf. Ezek 28:13; Gen 2-3). The cedar has surpassed even the Eden trees — the ultimate cosmic comparison. This connects to the Eden-fall pattern of ch 28 (the prince of Tyre): the most beautiful creature in the divine garden is the one most prone to pride and fall.</p>",
    "9": "<p><strong>yafe asitiv berob daliytav</strong> ('I made him beautiful with his many branches'): YHWH claims the beauty as his own gift — the creator made the cedar beautiful, which means the cedar's beauty belongs to the creator, not to the cedar. <strong>vayekanehu kol-atzei eden asher began haelohim</strong> ('so that all the trees of Eden in the garden of God envied him'): the Eden-trees envious of the supremely beautiful cedar. The divine garden as the standard of cosmic beauty, now surpassed by Assyria (= Egypt). The claim to be greater than Eden is the ultimate hubris.</p>",
    "10": "<p><strong>tachath asher gavah qomato</strong> ('because it grew tall'): the exact mechanism of the fall — the height itself is the problem. <strong>vayyarem libbov bego'vo</strong> ('its heart was proud of its height'): <em>rum lev</em> (H7311 + H3820, heart lifted up/proud) — the proud heart that Deut 8:14 and 17:20 warned against. The tree's pride is described as an interior condition (a 'heart') — Ezekiel consistently anatomizes pride as an inward movement before it manifests in outward action.</p>",
    "11": "<p><strong>vaettnenu beyad el-goyim aasor aaseh lo</strong> ('I gave him over to the hand of the mightiest of nations'): <em>el-goyim</em> ('the mightiest of nations') = Babylon, YHWH's designated executor. The Niphal <em>aasor</em> — 'to deal with/act against' — the conquering nation as the agent of the divine judgment against the proud tree. <strong>berish'ato gerashtihu</strong> ('I drove him out for his wickedness'): <em>garash</em> (H1644, drive out/expel) — the same word for Adam and Eve's expulsion from Eden (Gen 3:24), and for the Canaanites' expulsion before Israel (Exod 23:28-31). The pattern: beauty, pride, expulsion from the garden/realm.</p>",
    "12": "<p><strong>vayikretahu zarim araritzei goyim</strong> ('foreigners — the most ruthless of nations — cut him down'): the great cedar felled by the most ruthless peoples. The branches on the mountains, ravines, valleys — the scattered branches of a fallen empire. <strong>yazavu tzilo kol-ammei aretz</strong> ('all the peoples of the earth departed from his shade'): the shelter that the tree provided (v.6) is gone; the nations that dwelt in its shade now abandon it. Political alliances evaporate with power.</p>",
    "13": "<p>After the fall, the same birds and beasts that nested in the cedar (v.6) now inhabit the fallen trunk — not as sheltered guests but as scavengers on the corpse. The fallen empire's infrastructure is occupied by its former dependencies. The reversal of the living tree's hospitality into the dead tree's exploitation by creatures is a powerful image of imperial collapse.</p>",
    "14": "<p><strong>lema'an asher lo yigbehu kol-atzei hamayim</strong> ('so that no tree beside the waters may exalt itself'): the fall of the great cedar is a lesson for all great trees — no water-nourished power should lift itself in pride. <strong>netenum el-mot el-eretz tachetit</strong> ('for all who drink water are given over to death, to the depths of the earth'): the universality of mortality even for the greatest: <em>mot</em> (death) and <em>eretz tachetit</em> (the land beneath/Sheol) await all who grow tall. The phrase <em>betouch benei adam el-yordei bor</em> ('among the children of men, with those who go down to the Pit') — all human greatness shares the mortality that the Pit/Sheol represents.</p>",
    "15": "<p><strong>beyom ridto sheolah</strong> ('on the day he went down to Sheol'): <em>Sheol</em> (H7585, the underworld/realm of the dead) — Ezekiel's abundant use of Sheol vocabulary in these Egypt chapters (31:14-17; 32:17-32) is distinctive. <strong>kissiyt alav et-tehom</strong> ('I covered the deep over him'): the same <em>tehom</em> that nourished the cedar (v.4) now becomes its burial shroud — the waters that supported its life become the waters of death. <strong>vatit'abbal alav levanon</strong> ('I made Lebanon mourn for him'): Lebanon personified, mourning the loss of its signature tree/empire — the landscape itself grieves.</p>",
    "16": "<p><strong>miqqol mappelo hirgashti goyim</strong> ('I made the nations shake at the sound of his fall'): the resonance of a great empire's fall — nations trembling at the sound. <strong>vayinnachamu begei eretz tachetit kol atzei eden mivchar vetov levanon</strong> ('and all the trees of Eden... were comforted in the realm below'): the remarkable 'comfort' of the Eden-trees in Sheol at seeing the great cedar join them. The underworld receives the most exalted as equals; death is the great leveler.</p>",
    "17": "<p><strong>vegam-hem itav yaredu sheolah</strong> ('they too went down to Sheol with him'): the tree's <em>zeroa</em> (H2220, arm/strength — those allied with Assyria) share its fate. The empire takes its dependents with it into death. <em>el-chalalei-cherev</em> ('to those slain by the sword') — military death as the path to Sheol, contrasted with the honorable burial of those who die at peace.</p>",
    "18": "<p><strong>el-mi damita kachah bichavod uvegodel batzei eden</strong> ('to whom are you like in glory and greatness among the trees of Eden?'): the rhetorical question of v.2 is answered: Pharaoh is like all the great trees of Eden, all of whom have gone down. <strong>vetushav veshachavta bein arelim</strong> ('you too will be brought down... and lie among the uncircumcised'): <em>arel</em> (H6189, uncircumcised) — in the OT, to lie with the uncircumcised in Sheol is to share the shame of those outside the covenant (cf. 32:19-32). The honored burial of the circumcised versus the shameful mass grave of the uncircumcised: Pharaoh's final address places him outside the dignity of covenant membership in death.</p>"
  },
  "32": {
    "1": "<p>Date: twelfth year, twelfth month, first day — March 585 BCE, eight months after Jerusalem's fall. The second lamentation over Pharaoh comes after the catastrophe Ezekiel had prophesied — now the fall of Egypt can be seen in light of the confirmed fall of Jerusalem.</p>",
    "2": "<p><strong>sa qinah al-paro</strong> ('raise a lamentation over Pharaoh'): the second <em>qinah</em> (H7015, dirge/elegy) for Pharaoh — ch 19's lion/vine dirge for Israel's kings is now applied to Egypt's king. <strong>kelefir goyim domita veatta katannim bayammim</strong> ('you were like a young lion among the nations, and like a monster in the seas'): <em>tannin</em> (H8577) again — the sea-dragon of ch 29. But the comparison is complex: Pharaoh <em>thought</em> he was a young lion (<em>kephir</em>, H3715, the prime young lion) but was actually the sea-monster that roils the waters — a chaos creature rather than a royal beast.</p>",
    "3": "<p><strong>ufarsetti alecha et-reshet biqhal ammim rabbim</strong> ('I will throw my net over you with a host of many peoples'): YHWH as fisherman casting a net — the same fishing/netting imagery as 29:4, but now applied to the sea-monster context. The chaos creature caught in the divine net. <strong>veheeluka becharemi</strong> ('they will haul you up in my net'): the nations as YHWH's fishing tools, hauling up the tannin.</p>",
    "4": "<p><strong>venitashticha al-haaretz</strong> ('I will throw you on dry land'): the sea-monster removed from its element — the fish out of water. The birds and beasts consuming Pharaoh (v.4) reverse the images of Egyptian religious power: the sacred ibis, vulture, and crocodile, all representations of Egyptian deities, will feed on the corpse of the divine king.</p>",
    "5": "<p><strong>venatatti et-besarecha al-heharim</strong> ('I will lay your flesh on the mountains'): the empire's vast body (<em>basar</em>, H1320, flesh/body) scattered over mountains and valleys — the geographic distribution of the Egyptian corpse across the landscape. The image of an empire's remains spread across a broad terrain captures both the scale of the defeat and its permanence.</p>",
    "6": "<p><strong>vehishqeiti eretz tzafecha midamecha</strong> ('I will drench the land with your flowing blood'): the blood that flows from the corpse as a flood — the blood-drenching reverses the Nile flood that made Egypt's agriculture possible. The Nile that gave life through flooding becomes the blood-flood of death. <strong>el-heharim umilleu hayaqot</strong> ('even to the mountains, the ravines will be filled'): the blood reaches everywhere, the inverse of the Nile's life-giving overflow.</p>",
    "7": "<p><strong>uvchasoti bekhavotecha et-shamayim</strong> ('when I blot you out I will cover the heavens'): cosmic darkness accompanying Egypt's fall — the darkening of celestial bodies. <strong>vehishchakti et-shimsha beanav uyare'ach lo-ya'ir oro</strong> ('I will cover the sun with a cloud and the moon will not give its light'): solar and lunar eclipse as divine signs of judgment. This imagery appears in the Day of the LORD texts (Joel 2:10,31; 3:15; Amos 8:9) and in NT eschatological contexts (Matt 24:29; Rev 6:12-13). The darkening of Egypt's lights is both literal (smoke and darkness of conquest) and metaphorical (the end of Egyptian civilization's 'light' to the world).</p>",
    "8": "<p><strong>kol-meoroth hameeor bashamayim achasheet alecha</strong> ('all the luminous lights of the sky I will darken over you'): the comprehensive darkening — sun, moon, stars, all lights extinguished. Egypt was the civilization of Ra/sun worship; to darken the sun over Egypt is to defeat the deity Egypt trusted. The theological polemic is precise: the god Egypt worshiped cannot protect it; the God Egypt ignored is the one who controls all lights.</p>",
    "9": "<p><strong>vekaastu lev ammim rabbim</strong> ('I will trouble the hearts of many peoples'): <em>kaas</em> (H3707, provoke/trouble/grieve) — the psychological ripple effect of Egypt's fall. Nations that organized their world around Egyptian power as the regional anchor will be destabilized. <strong>el-aratzot asher lo yedatum</strong> ('to countries you have not known'): the scope of the trouble extends beyond Egypt's immediate neighbors to distant lands — a universal shock.</p>",
    "10": "<p><strong>vehashimoti alecha ammim rabbim</strong> ('I will appall many peoples over you'): <em>shamem</em> (H8074, be desolate/appalled) — the same word for the land's desolation applied here to the nations' psychological response. <strong>vemalkeihem yisaaru alecha sareer</strong> ('and their kings will shudder with horror when I brandish my sword before them'): <em>saar</em> (H8175, shudder/shiver/tremble) — visceral fear in the rulers when they see the sword of judgment fall on the greatest empire of the age.</p>",
    "11": "<p><strong>cherev melek bavel tevoaka</strong> ('the sword of the king of Babylon will come against you'): the explicit naming of the human instrument after the extended cosmic imagery (vv.7-10). The celestial phenomena of darkness and the political reality of the Babylonian military are two descriptions of the same event: YHWH's judgment executed through history.</p>",
    "12": "<p><strong>vehippilti hamonech bechorvot gibborim araritzei goyim culam</strong> ('I will cause your multitude to fall by the swords of the mighty — the most ruthless of nations, all of them'): <em>gibborim</em> (H1368, mighty warriors/heroes) — the elite warriors; <em>araritzei goyim</em> again. <strong>vegadevu et-gon mitzraim</strong> ('they will destroy the pride of Egypt'): <em>gaon mitzraim</em> — Egypt's pride, the word used in 30:6. The pride that characterized Egypt from v.3 ('my Nile — I made it') is the specific target of the judgment's destruction.</p>",
    "13": "<p><strong>vehibadeti et-kol-behemtah mealy mayim rabbim</strong> ('I will destroy all its livestock from beside the great waters'): the pastureland fed by the Nile — Egypt's agricultural wealth dependent on the river's overflow. <strong>velo tedolel maregel adam od</strong> ('no human foot will trouble them anymore'): the silence after destruction — no more footsteps in the devastated land, no more cattle-hooves disturbing the river. The peace of desolation.</p>",
    "14": "<p><strong>az ashiq meimehem veneharehem kashesmen azilem</strong> ('then I will let their waters settle and cause their rivers to flow like oil'): the paradoxical peace of the post-judgment Nile — waters no longer muddied by Pharaoh's thrashing (cf. 29:3), running smooth as oil. The oracle that began with Pharaoh muddying the waters (32:2) ends with the waters cleared of his disturbance.</p>",
    "15": "<p><strong>beten et-eretz mitzraim shemamah</strong> ('when I make the land of Egypt desolate'): the recognition formula anchors the chapter's conclusion — the cosmic darkness, the military defeat, the silenced waters: all serve the epistemological purpose of YHWH's self-disclosure. The end of Egypt as a great power is the means by which the nations will know the LORD.</p>",
    "16": "<p><strong>qinah hi veqonenuha</strong> ('this is the lamentation they will sing over her'): the meta-statement about the oracle's genre, identical in structure to 19:14 ('this is a lamentation and has been used as a lamentation'). The daughters of the nations (<em>benot goyim</em>) sing the lamentation — the mourning women of antiquity who formalized communal grief. Egypt receives the same funeral rite that a great city deserves, pronounced by the nations over whom it once exercised power.</p>",
    "17": "<p>A third date within the Egypt section: twelfth year, fifteenth of the month (month unspecified — likely the same twelfth month, two weeks after v.1). The descent-to-Sheol oracle (vv.17-32) is the most extended underworld passage in the OT outside of Isaiah 14.</p>",
    "18": "<p><strong>ben-adam naleh el-hamon mitzraim</strong> ('son of man, wail for the multitude of Egypt'): <em>naleh</em> (H5098, wail/growl/roar) — a different and stronger word than standard mourning verbs; the prophet's wailing drags Egypt down. <strong>vehored otah ve-et-benot goyim adamot</strong> ('bring them down — both Egypt and the daughters of the majestic nations'): the command to bring nations down to Sheol is prophetic speech-act — the oracle performs what it describes. The mourning song of the prophet is simultaneously the vehicle of descent.</p>",
    "19": "<p><strong>mimi naamt redi vehashshkab et-arelim</strong> ('whom do you surpass in beauty? Go down and lie with the uncircumcised'): the contempt of the invitation — Egypt's beauty (<em>naom</em>, H5278, pleasantness/beauty) is dismissed; the invitation to lie with the uncircumcised is ironic hospitality. <em>arel</em> (H6189, uncircumcised) — in the Sheol roll-call that follows, 'uncircumcised' is the mark of those who died in disgrace outside the covenant community. For Egypt to be uncircumcised is also ironic: Egyptian males were circumcised (Herodotus 2.36-37; Gen 34:9-10), yet the theological uncircumcision of their hearts (Jer 9:25-26; Ezek 44:7-9) places them with the covenant-excluded.</p>",
    "20": "<p><strong>betoch chalalei-cherev yipolu</strong> ('they will fall among those slain by the sword'): the military death as the entry point to Sheol. <strong>cherev nitanah meshochahu vekol-hamoneiha</strong> ('Egypt is delivered to the sword — draw her down with all her multitude'): the sword as the agent of the descent, delivering Egypt to Sheol along with its entire <em>hamon</em> (multitude/wealth).</p>",
    "21": "<p><strong>yedaberu-lo elei gibborim mitoch sheol</strong> ('the mightiest warriors will speak to him from the midst of Sheol'): the underworld as a place of ongoing speech — the shades of mighty warriors addressing the newly-arrived Pharaoh. This is the most developed OT picture of Sheol as a realm with inhabitants (cf. Isa 14:9-11 where Sheol's rulers rise to greet the king of Babylon). <strong>mehelai-cherev yeredu shachvu arelim</strong> ('slain by the sword, they have gone down, lying uncircumcised'): the entrance formula for Sheol in this passage.</p>",
    "22": "<p><strong>sham ashur vechal-qahalah</strong> ('Assyria is there with all its company'): the great empire catalog begins — Assyria, which fell to Babylon (612 BCE), is already in Sheol. The Assyrian army's graves surround it — the dead empire retains its military formation in death, but now it is a formation of graves, not fighting units. The parade of fallen empires makes the theological point: no nation that has lorded its power over others escapes the common fate.</p>",
    "23": "<p><strong>qivroteiha beyrketei-bor</strong> ('its graves are in the depths of the Pit'): <em>bor</em> (H953, pit/cistern/dungeon) — the underworld pit. The Assyrian army's graves in the depths, 'gathered around its tomb' — even in death, the military structure is maintained as a grotesque formation of corpses. <strong>asher-nateenu chittit bearetz chayyim</strong> ('who had spread terror in the land of the living'): the refrain that appears for each nation — their power was measured by the terror they induced; in Sheol, that terror is silenced.</p>",
    "24": "<p><strong>sham elam vechal-hamonah</strong> ('Elam is there with all its multitude'): Elam, the ancient Mesopotamian kingdom east of Babylon — its bowmen were famous in antiquity (Isa 22:6; Jer 49:34-39). <strong>arelim yoredei eretz tachetit</strong> ('uncircumcised, gone down to the depths of the earth'): the shame-formula — lying in Sheol among the uncircumcised, despite having spread terror. The equation of military might with shame in death is the chapter's central theological move.</p>",
    "25": "<p>The description of Elam's grave-bed <em>betoch chalalim</em> ('among the slain') with graves surrounding it. <strong>veyutenat mishkavah vetoch chalalim</strong> — the ignominious grave 'among the slain' is the opposite of honorable burial (kingly tombs, family burial sites). Despite the terror spread among the living, the powerful end up in a common pit with the violently slain.</p>",
    "26": "<p><strong>sham meshech tuval vechal-hamonah</strong> ('Meshech and Tubal are there with all their multitude'): the northern peoples of Gen 10:2 (sons of Japheth) — often identified with areas in Asia Minor (Phrygia/Cappadocia). Their terror too is silenced in Sheol. These are the same peoples of Gog (Ezek 38-39), completing the catalog of northern, eastern, and western powers.</p>",
    "27": "<p><strong>velo yishkevu et-gibborim nophlim mearelim</strong> ('do they not lie with the fallen warriors of old who went down to Sheol with their weapons?'): the 'warriors of old' (<em>nophlim me-arelim</em> or <em>gibborim meolam</em>) — possibly a reference to the ancient heroes/Nephilim of Gen 6:4. The ancient warriors went to Sheol with their weapons, weapons placed under their heads and shields covering their bones — honorable warrior burial. But Meshech and Tubal lie differently: not as honored warriors but as those who spread terror without receiving the honor of proper warrior burial.</p>",
    "28": "<p><strong>veattah betoch arelim tishaver</strong> ('you too will be shattered among the uncircumcised'): Pharaoh, addressed directly, joins the roll-call. The catalog moves from third-person descriptions (Assyria, Elam, Meshech-Tubal, Edom) to second-person address: <em>you</em> will be shattered among them. The roll-call is not a historical survey but an address to the living king — this is what awaits you.</p>",
    "29": "<p><strong>sham edom melacheha vechal-nesieiha</strong> ('Edom is there — its kings and all its princes'): Edom, despite being south of Israel rather than north, is included. The catalog is arranged by symbolic weight rather than geography. Edom as the perpetual enemy of Jacob/Israel (from Gen 25 onward, through the Esau-Jacob conflict) receives no more special treatment in Sheol than any other nation. <em>bechol-geburtam</em> ('despite their might'): the great leveling — might does not exempt from Sheol's common shame.</p>",
    "30": "<p><strong>sham nasichei tzaphon kulam vesidoni</strong> ('there are all the princes of the north and all the Sidonians'): the 'princes of the north' = Aramean kingdoms; Sidon = Phoenicia. The fear they inspired (<em>chetit mig'vurtam</em>, 'terror from their might') is gone; they lie in shame with the slain. The geography of the roll-call — Assyria (northeast), Elam (east), Meshech-Tubal (north), Edom (south), northern princes and Sidon (northwest) — encompasses the entire known world around Egypt. Pharaoh will be joined by every regional power.</p>",
    "31": "<p><strong>otam yireh paro venecham</strong> ('when Pharaoh sees them he will be comforted over all his multitude'): dark comfort — Pharaoh will find consolation in seeing that all the great powers share his fate. The comfort of shared shame is the only comfort Sheol offers. <em>nacham</em> (H5162, comfort/console) — the word used for genuine divine consolation (Isa 40:1; 51:12) here inverted: the comfort of the underworld is merely that misery has company.</p>",
    "32": "<p><strong>ki-natati chitti bearetz chayyim</strong> ('for I spread his terror in the land of the living'): YHWH acknowledges that Pharaoh's terror (<em>chitti</em>, from <em>chat</em>, H2844, terror) was real — but it was YHWH who gave it to him, and YHWH who now withdraws it. The final clause <em>veyushkav et-paro vekhol-hamono bein arelim</em> ('Pharaoh and all his multitude will be laid among the uncircumcised') closes the entire four-chapter Egypt section with the verdict: despite greatness, power, beauty, and terror, Egypt's end is the common grave of the uncircumcised. The claim 'my Nile — I made it' (29:3) ends in a grave among those outside the covenant.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'ezekiel')
    merge_comm(existing, EZK_ORIG)
    save_comm('mkt-original', 'ezekiel', existing)

    out = json.loads((ROOT / 'data/commentary/mkt-original/ezekiel.json').read_text())
    il  = json.loads((ROOT / 'data/interlinear/ezekiel.json').read_text())

    all_ok = True
    for ch in [29, 30, 31, 32]:
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
